import axios from 'axios';

// API Configuration
const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Create axios instance with enhanced configuration
const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 60000,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Request interceptor
api.interceptors.request.use(
  (config) => {
    if (process.env.NODE_ENV === 'development') {
      console.log(`🚀 API Request: ${config.method?.toUpperCase()} ${config.url}`, {
        baseURL: config.baseURL,
        fullURL: `${config.baseURL}${config.url}`,
        params: config.params,
        data: config.data ? 'Data included' : 'No data'
      });
    }
    
    const token = localStorage.getItem('authToken');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    
    return config;
  },
  (error) => {
    console.error('❌ Request interceptor error:', error);
    return Promise.reject(error);
  }
);

// Response interceptor
api.interceptors.response.use(
  (response) => {
    if (process.env.NODE_ENV === 'development') {
      console.log(`✅ API Response: ${response.config.method?.toUpperCase()} ${response.config.url}`, {
        status: response.status,
        data: response.data,
        success: response.data?.success
      });
    }
    return response;
  },
  (error) => {
    console.error(`❌ API Error: ${error.config?.method?.toUpperCase()} ${error.config?.url}`, {
      status: error.response?.status,
      statusText: error.response?.statusText,
      message: error.response?.data?.message || error.message,
      responseData: error.response?.data,
      fullError: error
    });
    
    if (error.response?.status === 401) {
      localStorage.removeItem('authToken');
      if (window.location.pathname !== '/login') {
        window.location.href = '/login';
      }
    }
    
    return Promise.reject(error);
  }
);

// ============ ATTENDANCE API CALLS ============

export const captureAttendance = async (data) => {
  try {
    console.log('📸 Capturing attendance:', { classId: data.classId, hasImage: !!data.imageData });
    
    const response = await api.post('/attendance/capture', data, {
      timeout: 45000 // 45 seconds for camera processing
    });
    
    console.log('✅ Attendance captured successfully:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Capture attendance error:', error);
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to process camera capture' 
    };
  }
};

export const uploadPhotosForAttendance = async (data) => {
  try {
    // Validate input data
    if (!data.images || !Array.isArray(data.images) || data.images.length === 0) {
      throw { success: false, message: 'No images provided for upload' };
    }
    
    if (!data.classId) {
      throw { success: false, message: 'Class ID is required' };
    }
    
    console.log('📤 Uploading photos for attendance:', {
      imagesCount: data.images.length,
      classId: data.classId,
      uploadType: data.uploadType
    });
    
    const response = await api.post('/attendance/upload', data, {
      timeout: 120000, // 2 minutes for batch processing
      onUploadProgress: (progressEvent) => {
        if (progressEvent.total) {
          const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
          console.log(`📊 Upload Progress: ${percentCompleted}%`);
        }
      }
    });
    
    console.log('✅ Upload successful:', {
      success: response.data.success,
      recognizedCount: response.data.results?.recognizedStudents?.length || 0
    });
    
    return response.data;
  } catch (error) {
    console.error('❌ Upload photos error:', error);
    
    // Enhanced error handling
    if (error.code === 'ECONNABORTED') {
      throw { 
        success: false, 
        message: 'Upload timeout - please try with fewer images or check your connection' 
      };
    }
    
    if (error.response?.status === 413) {
      throw { 
        success: false, 
        message: 'Files too large - please reduce image sizes or upload fewer images' 
      };
    }
    
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to upload photos' 
    };
  }
};

export const uploadPhotosMultipart = async (formData) => {
  try {
    console.log('📤 Uploading photos via multipart');
    
    const response = await api.post('/attendance/upload-files', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      timeout: 120000,
      onUploadProgress: (progressEvent) => {
        if (progressEvent.total) {
          const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
          console.log(`📊 File Upload Progress: ${percentCompleted}%`);
        }
      }
    });
    
    console.log('✅ Multipart upload successful:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Multipart upload error:', error);
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to upload files' 
    };
  }
};

