    const response = await api.get(`/attendance/live/${classId}`, { params });
    
    console.log('✅ Live attendance data retrieved:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Get attendance data error:', error);
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to fetch attendance data' 
    };
  }
};

