    const response = await api.delete(`/attendance/${attendanceId}`);
    
    console.log('✅ Attendance record deleted:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Delete attendance record error:', error);
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to delete attendance record' 
    };
  }
};

// ============ STUDENTS API CALLS ============

export const registerStudent = async (studentData) => {
  try {
    // Validate required fields
    if (!studentData.studentId || !studentData.name) {
      throw { success: false, message: 'Student ID and name are required' };
    }
    
    console.log('👤 Registering student:', { 
      studentId: studentData.studentId, 
      name: studentData.name,
      hasFaceImages: !!studentData.faceImages
    });
    
    const response = await api.post('/students/register', studentData, {
      timeout: 90000 // 90 seconds for face encoding
    });
    
    console.log('✅ Student registered successfully:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Register student error:', error);
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to register student' 
    };
  }
};

export const getStudents = async (classId) => {
  try {
    console.log(`🔄 Getting students for class: ${classId}`);
    
    // Try multiple possible endpoints
    const endpoints = [
      `/students/class/${classId}`,
      `/students?classId=${classId}`,
      `/students/${classId}`,
      '/students'
    ];
    
    let response = null;
    let lastError = null;
    
    for (const endpoint of endpoints) {
      try {
        console.log(`🔍 Trying endpoint: ${endpoint}`);
        response = await api.get(endpoint);
        
        if (response.data) {
          console.log(`✅ Successfully got data from: ${endpoint}`, response.data);
          break;
        }
      } catch (err) {
        console.log(`⚠️ Endpoint ${endpoint} failed:`, err.response?.status, err.response?.data);
        lastError = err;
        continue;
      }
    }
    
    if (!response) {
      throw lastError || new Error('All student endpoints failed');
    }
    
    // Handle different response formats
    let students = [];
    const data = response.data;
    
    if (Array.isArray(data)) {
      students = data;
    } else if (data.students && Array.isArray(data.students)) {
      students = data.students;
    } else if (data.data && Array.isArray(data.data)) {
      students = data.data;
    } else if (data.success && data.students) {
      students = data.students;
    }
    
    console.log(`📊 Processed students data:`, {
      originalFormat: typeof data,
      studentsFound: students.length,
      sampleStudent: students[0] || null
    });
    
    return {
      success: true,
      students: students,
      message: `Found ${students.length} students`
    };
    
  } catch (error) {
    console.error('❌ Get students error:', error);
    return {
      success: false,
      students: [],
      message: error.response?.data?.message || error.message || 'Failed to fetch students',
      error: error.response?.data || error.message
    };
  }
};

