// ============ ATTENDANCE DATA API CALLS ============

export const getMonthlyAttendance = async (classId, month, year) => {
  try {
    console.log(`🔄 Getting monthly attendance:`, { classId, month, year });
    
    const endpoints = [
      `/attendance/monthly?classId=${classId}&month=${month}&year=${year}`,
      `/attendance/monthly/${classId}?month=${month}&year=${year}`,
      `/attendance/monthly/${classId}/${month}/${year}`,
      `/attendance?classId=${classId}&month=${month}&year=${year}&type=monthly`
    ];
    
    let response = null;
    let lastError = null;
    
    for (const endpoint of endpoints) {
      try {
        console.log(`🔍 Trying attendance endpoint: ${endpoint}`);
        response = await api.get(endpoint);
        
        if (response.data) {
          console.log(`✅ Successfully got attendance from: ${endpoint}`, response.data);
          break;
        }
      } catch (err) {
        console.log(`⚠️ Attendance endpoint ${endpoint} failed:`, err.response?.status);
        lastError = err;
        continue;
      }
    }
    
    if (!response) {
      throw lastError || new Error('All attendance endpoints failed');
    }
    
    // Handle different response formats
    const data = response.data;
    let attendance = [];
    let students = [];
    let statistics = {};
    
    if (Array.isArray(data)) {
      attendance = data;
    } else if (data.attendance) {
      attendance = data.attendance;
      students = data.students || [];
      statistics = data.statistics || {};
    } else if (data.data) {
      attendance = data.data;
    }
    
    return {
      success: true,
      attendance: attendance,
      students: students,
      statistics: statistics
    };
    
  } catch (error) {
    console.error('❌ Get monthly attendance error:', error);
    return {
      success: false,
      attendance: [],
      students: [],
      statistics: {},
      message: error.response?.data?.message || error.message || 'Failed to fetch monthly attendance'
    };
