export const uploadFaceImages = async (studentId, faceFiles) => {
  try {
    console.log('👤 Uploading face images for student:', studentId);
    
    const formData = new FormData();
    faceFiles.forEach((file, index) => {
      formData.append('faces', file);
    });
    
    const response = await api.post(`/upload/faces/${studentId}`, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      timeout: 60000
    });
    
    console.log('✅ Face images uploaded:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Upload face images error:', error);
    throw error.response?.data || { 
      success: false, 
      message: error.message || 'Failed to upload face images' 
    };
  }
};

export const uploadCSV = async (csvFile) => {
  try {
    console.log('📄 Uploading CSV file');
    
    const formData = new FormData();
    formData.append('csvFile', csvFile);
    
    const response = await api.post('/upload/students-csv', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
